.vault-card {
  border: 1px solid var(--card-border);
  border-radius: var(--card-radius);
  padding: var(--card-padding);
  display: flex;
  flex-direction: column;
  gap: 1.2vw;
}

.ssc {
  position: relative;
  width: 100vw;
}

.ssc__sticky {
  position: sticky;
  top: 0;
  display: flex;
  height: 100vh;
  width: 100vw;
  align-items: center;
  justify-content: center;
  overflow: hidden;
}

.ssc__cards {
  position: relative;
  z-index: 1;
  display: flex;
  height: fit-content;
  width: fit-content;
  align-items: center;
  justify-content: center;
}

.ssc__card-wrap {
  position: relative;
  height: fit-content;
  width: fit-content;
  flex-shrink: 0;
  will-change: transform;
}

.ssc__card {
  height: 30vw !important;
  width: 25vw !important;
  flex-shrink: 0;
  overflow: hidden;
}

.ssc__card-inner {
  display: flex;
  height: 100%;
  width: 100%;
  flex-direction: column;
  justify-content: space-between;
  padding: 2.5vw 1.5vw 1.2vw;
}

.ssc__card-top {
  display: flex;
  flex-direction: column;
  gap: 1.2vw;
}

.ssc__eyebrow {
  font-size: 0.85vw;
  font-weight: 600;
  letter-spacing: 0.2em;
  line-height: 1;
  text-transform: uppercase;
}

.ssc__description {
  width: 85%;
  font-size: 1.05vw;
  line-height: 1.35;
}

.ssc__title {
  font-size: 4.6vw;
  font-weight: 600;
  line-height: 0.78;
}

.ssc__heading-wrap {
  pointer-events: none;
  position: absolute;
  inset: 0;
  z-index: 0;
  display: flex;
  align-items: center;
  justify-content: center;
}

.ssc__heading {
  width: 100%;
  padding-inline: 2vw;
  text-align: center;
  font-size: 5.5vw;
  font-weight: 600;
  line-height: 0.95;
  color: #1a1a1a;
}

@media (max-width: 1024px) {
  .ssc__cards {
    gap: 4vw !important;
  }

  .ssc__card {
    height: 42vw !important;
    width: 34vw !important;
  }

  .ssc__card-inner {
    padding: 3vw 2vw 1.8vw;
  }

  .ssc__card-top {
    gap: 1.8vw;
  }

  .ssc__eyebrow {
    font-size: 1.3vw;
  }

  .ssc__description {
    width: 92%;
    font-size: 1.5vw;
  }

  .ssc__title {
    font-size: 6vw;
  }

  .ssc__heading {
    font-size: 7.5vw;
  }
}

@media (max-width: 767px) {
  .ssc__cards {
    gap: 3vw !important;
  }

  .ssc__card {
    height: 78vw !important;
    width: 62vw !important;
  }

  .ssc__card-inner {
    padding: 4.5vw 4vw 3vw;
  }

  .ssc__card-top {
    gap: 3.2vw;
  }

  .ssc__eyebrow {
    font-size: 2.4vw;
  }

  .ssc__description {
    width: 100%;
    font-size: 3.2vw;
    line-height: 1.35;
  }

  .ssc__title {
    font-size: 9vw;
    line-height: 0.86;
  }

  .ssc__heading {
    padding-inline: 4vw;
    font-size: 10vw;
  }
}

"use client";

import { useEffect, useMemo, useRef } from "react";
import gsap from "gsap";
import ScrollTrigger from "gsap/dist/ScrollTrigger";
import "./scroll-shuffled-cards.css";

gsap.registerPlugin(ScrollTrigger);

const getRandomInRange = (min, max) => Math.random() * (max - min) + min;

function VaultCard({
  children,
  padding = "2vw",
  borderColor = "rgba(0,0,0,0.2)",
  radius = "1.2vw",
  className = "",
  style,
}) {
  return (
    <div
      className={`vault-card ${className}`}
      style={{
        "--card-padding": padding,
        "--card-border": borderColor,
        "--card-radius": radius,
        ...style,
      }}
    >
      {children}
    </div>
  );
}

export default function ScrollShuffledCards({
  cards = [],
  heading = "Scroll Shuffled Cards",
  sectionHeight = 400,
  cardWidth = "25vw",
  cardHeight = "30vw",
  cardPadding = "0.25vw",
  cardRadius = "0vw",
  cardsGap = "6vw",
  background = "#FFFBEB",
  initialContainerXPercent = 100,
  finalContainerXPercent = -100,
  startXRange = [-4, 4],
  startYRange = [-4, 4],
  startRotateRange = [-6, 6],
  endXRange = [-20, 30],
  endYRange = [-10, 10],
  endRotateRange = [-10, 10],
  className = "",
}) {
  const sectionRef = useRef(null);
  const containerRef = useRef(null);
  const cardRefs = useRef([]);

  const randomizedCards = useMemo(
    () =>
      cards.map((card, index) => ({
        ...card,
        startX: getRandomInRange(startXRange[0], startXRange[1]),
        startY: getRandomInRange(startYRange[0], startYRange[1]),
        startRotate: getRandomInRange(startRotateRange[0], startRotateRange[1]),
        endX: getRandomInRange(endXRange[0], endXRange[1]),
        endY: getRandomInRange(endYRange[0], endYRange[1]),
        endRotate: getRandomInRange(endRotateRange[0], endRotateRange[1]),
        zIndex: cards.length - index,
      })),
    [cards, endRotateRange, endXRange, endYRange, startRotateRange, startXRange, startYRange]
  );

  useEffect(() => {
    cardRefs.current = cardRefs.current.slice(0, randomizedCards.length);

    const context = gsap.context(() => {
      const cardElements = cardRefs.current.filter(Boolean);
      if (!cardElements.length) return;

      gsap.set(containerRef.current, {
        xPercent: initialContainerXPercent,
      });

      cardElements.forEach((cardElement, index) => {
        gsap.set(cardElement, {
          x: `${randomizedCards[index].startX}vw`,
          y: `${randomizedCards[index].startY}vw`,
          rotation: randomizedCards[index].startRotate,
        });
      });

      const timeline = gsap.timeline({
        scrollTrigger: {
          trigger: sectionRef.current,
          start: "top top",
          end: "bottom bottom",
          scrub: true,
        },
      });

      timeline.to(
        containerRef.current,
        {
          xPercent: finalContainerXPercent,
          ease: "none",
        },
        0
      );

      cardElements.forEach((cardElement, index) => {
        timeline.to(
          cardElement,
          {
            x: `${randomizedCards[index].endX}vw`,
            y: `${randomizedCards[index].endY}vw`,
            rotation: randomizedCards[index].endRotate,
            ease: "none",
          },
          0
        );
      });
    }, sectionRef);

    return () => context.revert();
  }, [finalContainerXPercent, initialContainerXPercent, randomizedCards]);

  return (
    <section
      ref={sectionRef}
      className={`ssc ${className}`}
      style={{ height: `${sectionHeight}vh`, background }}
    >
      <div className="ssc__sticky">
        <div ref={containerRef} className="ssc__cards" style={{ gap: cardsGap }}>
          {randomizedCards.map((card, index) => (
            <div
              key={card.id ?? index}
              ref={(element) => {
                cardRefs.current[index] = element;
              }}
              className="ssc__card-wrap"
              style={{ zIndex: card.zIndex }}
            >
              <VaultCard
                radius={cardRadius}
                padding={cardPadding}
                className={`ssc__card ${card.bgOuter || ""}`}
                style={{ width: cardWidth, height: cardHeight }}
              >
                <div className={`ssc__card-inner ${card.bgInner || ""} ${card.text || ""}`}>
                  <div className="ssc__card-top">
                    {card.eyebrow ? <span className="ssc__eyebrow">{card.eyebrow}</span> : null}
                    {card.description ? (
                      <p className="ssc__description">{card.description}</p>
                    ) : null}
                  </div>
                  {card.title ? <h2 className="ssc__title">{card.title}</h2> : null}
                </div>
              </VaultCard>
            </div>
          ))}
        </div>

        <div className="ssc__heading-wrap">
          <h1 className="ssc__heading">{heading}</h1>
        </div>
      </div>
    </section>
  );
}
